{
  "name": "Subas-tica",
  "description": "Plataforma de subastas dinámicas para eventos presenciales con enfoque en ganado y gestión multi-puja en tiempo real.",
  "requestFramePermissions": [
    "camera"
  ]
}

export enum UserRole {
  ADMIN = 'ADMIN',
  SELLER = 'SELLER',
  BUYER = 'BUYER',
  VIEWER = 'VIEWER'
}

export enum ItemStatus {
  AVAILABLE = 'AVAILABLE', // Exhibición
  WITH_INTEREST = 'WITH_INTEREST',
  READY_TO_ACTIVATE = 'READY_TO_ACTIVATE',
  ACTIVE_BIDDING = 'ACTIVE_BIDDING',
  PAUSED = 'PAUSED',
  CLOSED = 'CLOSED',
  ADJUDICATED = 'ADJUDICATED',
  PAID = 'PAID',
  SETTLED = 'SETTLED',
  DESERTED = 'DESERTED',
  CANCELLED = 'CANCELLED'
}

export enum BidStatus {
  NOT_STARTED = 'NOT_STARTED',
  ACTIVE = 'ACTIVE',
  PAUSED = 'PAUSED',
  CLOSED = 'CLOSED',
  ANNULLED = 'ANNULLED'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  phone: string;
  identification: string;
}

export interface CattleData {
  breed: string;
  weight: number;
  age: number;
  sex: 'MACHO' | 'HEMBRA';
  condition: string;
  vetNotes?: string;
}

export interface AuctionItem {
  id: string;
  number: number;
  title: string;
  description: string;
  imageUrl: string;
  sellerId: string;
  status: ItemStatus;
  basePrice: number;
  minIncrement: number;
  reservePrice?: number;
  isCattle: boolean;
  cattleData?: CattleData;
  interestedUserIds: string[];
  buyIntentUserIds: string[];
  currentBid?: number;
  winnerId?: string;
  endTime?: number; // timestamp
}

export interface BidEntry {
  id: string;
  itemId: string;
  userId: string;
  amount: number;
  timestamp: number;
}

export interface AuctionState {
  items: AuctionItem[];
  bids: BidEntry[];
  currentUser: User | null;
  activeEventName: string;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter as Router, Routes, Route, Navigate, Link } from 'react-router-dom';
import { 
  User, 
  UserRole, 
  AuctionItem, 
  ItemStatus, 
  BidEntry 
} from './types';
import { MOCK_ITEMS } from './constants';

// Layout Components
import Navbar from './components/Navbar';
import LandingPage from './views/LandingPage';
import BuyerDashboard from './views/BuyerDashboard';
import AdminDashboard from './views/AdminDashboard';
import ItemDetail from './views/ItemDetail';
import SellerDashboard from './views/SellerDashboard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('subastica_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [items, setItems] = useState<AuctionItem[]>(() => {
    const saved = localStorage.getItem('subastica_items');
    return saved ? JSON.parse(saved) : MOCK_ITEMS;
  });

  const [bids, setBids] = useState<BidEntry[]>(() => {
    const saved = localStorage.getItem('subastica_bids');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist state
  useEffect(() => {
    localStorage.setItem('subastica_items', JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem('subastica_bids', JSON.stringify(bids));
  }, [bids]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('subastica_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('subastica_user');
  };

  const updateItemStatus = (itemId: string, status: ItemStatus) => {
    setItems(prev => prev.map(item => 
      item.id === itemId ? { ...item, status } : item
    ));
  };

  const handleInterest = (itemId: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === itemId) {
        const isInterested = item.interestedUserIds.includes(currentUser.id);
        const newList = isInterested 
          ? item.interestedUserIds.filter(id => id !== currentUser.id)
          : [...item.interestedUserIds, currentUser.id];

        let newStatus = item.status;
        if (newList.length > 0 && item.status === ItemStatus.AVAILABLE) {
          newStatus = ItemStatus.WITH_INTEREST;
        } else if (newList.length === 0 && item.status === ItemStatus.WITH_INTEREST) {
          newStatus = ItemStatus.AVAILABLE;
        }

        return { ...item, interestedUserIds: newList, status: newStatus };
      }
      return item;
    }));
  };

  const handleBuyIntent = (itemId: string) => {
    if (!currentUser) return;
    setItems(prev => prev.map(item => {
      if (item.id === itemId) {
        const hasIntent = item.buyIntentUserIds.includes(currentUser.id);
        const newList = hasIntent
          ? item.buyIntentUserIds.filter(id => id !== currentUser.id)
          : [...item.buyIntentUserIds, currentUser.id];

        let newStatus = item.status;
        if (newList.length > 0) {
          newStatus = ItemStatus.READY_TO_ACTIVATE;
        } else if (item.interestedUserIds.length > 0) {
          newStatus = ItemStatus.WITH_INTEREST;
        } else {
          newStatus = ItemStatus.AVAILABLE;
        }

        return { ...item, buyIntentUserIds: newList, status: newStatus };
      }
      return item;
    }));
  };

  const placeBid = (itemId: string, amount: number) => {
    if (!currentUser) return;
    const item = items.find(i => i.id === itemId);
    if (!item || item.status !== ItemStatus.ACTIVE_BIDDING) return;

    // Validate bid
    const currentPrice = item.currentBid || item.basePrice;
    if (amount < currentPrice + item.minIncrement) {
      alert(`La oferta debe ser al menos ${currentPrice + item.minIncrement}`);
      return;
    }

    const newBid: BidEntry = {
      id: Math.random().toString(36).substr(2, 9),
      itemId,
      userId: currentUser.id,
      amount,
      timestamp: Date.now()
    };

    setBids(prev => [...prev, newBid]);
    setItems(prev => prev.map(i => {
      if (i.id === itemId) {
        // Anti-sniping: if less than 30s left, extend by 30s
        const now = Date.now();
        const remaining = (i.endTime || 0) - now;
        let newEndTime = i.endTime;
        if (remaining > 0 && remaining < 30000) {
          newEndTime = now + 30000;
        }
        return { ...i, currentBid: amount, endTime: newEndTime };
      }
      return i;
    }));
  };

  const activateBidding = (itemId: string, durationSeconds: number) => {
    setItems(prev => prev.map(item => {
      if (item.id === itemId) {
        return { 
          ...item, 
          status: ItemStatus.ACTIVE_BIDDING, 
          endTime: Date.now() + (durationSeconds * 1000) 
        };
      }
      return item;
    }));
  };

  const adjudicateItem = (itemId: string) => {
    setItems(prev => prev.map(item => {
      if (item.id === itemId) {
        const lastBid = bids.filter(b => b.itemId === itemId).sort((a,b) => b.amount - a.amount)[0];
        return { 
          ...item, 
          status: ItemStatus.ADJUDICATED,
          winnerId: lastBid?.userId 
        };
      }
      return item;
    }));
  };

  // Timer simulation for active bids
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      setItems(prev => prev.map(item => {
        if (item.status === ItemStatus.ACTIVE_BIDDING && item.endTime && now > item.endTime) {
          return { ...item, status: ItemStatus.CLOSED };
        }
        return item;
      }));
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <Router>
      <div className="min-h-screen flex flex-col">
        {currentUser && <Navbar user={currentUser} onLogout={handleLogout} />}

        <main className="flex-1 overflow-auto">
          <Routes>
            <Route 
              path="/" 
              element={currentUser ? <Navigate to={`/${currentUser.role.toLowerCase()}`} /> : <LandingPage onLogin={handleLogin} />} 
            />

            <Route 
              path="/buyer" 
              element={currentUser?.role === UserRole.BUYER ? 
                <BuyerDashboard items={items} onInterest={handleInterest} onBuyIntent={handleBuyIntent} userId={currentUser.id} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/admin" 
              element={currentUser?.role === UserRole.ADMIN ? 
                <AdminDashboard items={items} bids={bids} onActivate={activateBidding} onAdjudicate={adjudicateItem} onUpdateStatus={updateItemStatus} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/seller" 
              element={currentUser?.role === UserRole.SELLER ? 
                <SellerDashboard items={items} sellerId={currentUser.id} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/item/:id" 
              element={<ItemDetail 
                items={items} 
                bids={bids} 
                user={currentUser} 
                onInterest={handleInterest} 
                onBuyIntent={handleBuyIntent} 
                onBid={placeBid} 
              />} 
            />

            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        {/* Floating Mobile Scanner Overlay Simulated */}
        {currentUser?.role === UserRole.BUYER && (
          <div className="fixed bottom-6 right-6 z-50">
            <button 
              className="bg-blue-600 text-white p-4 rounded-full shadow-2xl hover:bg-blue-700 transition-transform active:scale-95 flex items-center justify-center"
              onClick={() => alert("Simulando Escaneo QR... Buscando ítem más cercano.")}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" />
              </svg>
            </button>
          </div>
        )}
      </div>
    </Router>
  );
};

export default App;

