import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { 
  User, 
  UserRole, 
  AuctionItem, 
  ItemStatus, 
  BidEntry 
} from './types';
import { supabase } from './supabase';

// Layout Components
import Navbar from './components/Navbar';
import LandingPage from './views/LandingPage';
import BuyerDashboard from './views/BuyerDashboard';
import AdminDashboard from './views/AdminDashboard';
import ItemDetail from './views/ItemDetail';
import SellerDashboard from './views/SellerDashboard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('subastica_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [items, setItems] = useState<AuctionItem[]>([]);
  const [bids, setBids] = useState<BidEntry[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // 1. Carga inicial y Suscripciones en Tiempo Real
  useEffect(() => {
    const fetchData = async () => {
      setIsLoading(true);
      const { data: initialItems } = await supabase.from('items').select('*').order('number', { ascending: true });
      const { data: initialBids } = await supabase.from('bids').select('*').order('timestamp', { ascending: false });

      if (initialItems) setItems(initialItems);
      if (initialBids) setBids(initialBids);
      setIsLoading(false);
    };

    fetchData();

    // Suscripción a cambios en items
    const itemsSubscription = supabase
      .channel('schema-db-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'items' }, (payload) => {
        if (payload.eventType === 'UPDATE') {
          setItems(current => current.map(item => item.id === payload.new.id ? payload.new as AuctionItem : item));
        } else if (payload.eventType === 'INSERT') {
          setItems(current => [...current, payload.new as AuctionItem]);
        }
      })
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'bids' }, (payload) => {
        setBids(current => [payload.new as BidEntry, ...current]);
      })
      .subscribe();

    return () => {
      supabase.removeChannel(itemsSubscription);
    };
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('subastica_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('subastica_user');
  };

  const updateItemStatus = async (itemId: string, status: ItemStatus) => {
    await supabase.from('items').update({ status }).eq('id', itemId);
  };

  const handleInterest = async (itemId: string) => {
    if (!currentUser) return;
    const item = items.find(i => i.id === itemId);
    if (!item) return;

    const isInterested = item.interestedUserIds.includes(currentUser.id);
    const newList = isInterested 
      ? item.interestedUserIds.filter(id => id !== currentUser.id)
      : [...item.interestedUserIds, currentUser.id];

    let newStatus = item.status;
    if (newList.length > 0 && item.status === ItemStatus.AVAILABLE) {
      newStatus = ItemStatus.WITH_INTEREST;
    } else if (newList.length === 0 && item.status === ItemStatus.WITH_INTEREST) {
      newStatus = ItemStatus.AVAILABLE;
    }

    await supabase.from('items').update({ 
      interestedUserIds: newList, 
      status: newStatus 
    }).eq('id', itemId);
  };

  const handleBuyIntent = async (itemId: string) => {
    if (!currentUser) return;
    const item = items.find(i => i.id === itemId);
    if (!item) return;

    const hasIntent = item.buyIntentUserIds.includes(currentUser.id);
    const newList = hasIntent
      ? item.buyIntentUserIds.filter(id => id !== currentUser.id)
      : [...item.buyIntentUserIds, currentUser.id];

    let newStatus = item.status;
    if (newList.length > 0) {
      newStatus = ItemStatus.READY_TO_ACTIVATE;
    } else if (item.interestedUserIds.length > 0) {
      newStatus = ItemStatus.WITH_INTEREST;
    } else {
      newStatus = ItemStatus.AVAILABLE;
    }

    await supabase.from('items').update({ 
      buyIntentUserIds: newList, 
      status: newStatus 
    }).eq('id', itemId);
  };

  const placeBid = async (itemId: string, amount: number) => {
    if (!currentUser) return;
    const item = items.find(i => i.id === itemId);
    if (!item || item.status !== ItemStatus.ACTIVE_BIDDING) return;

    const currentPrice = item.currentBid || item.basePrice;
    if (amount < currentPrice + item.minIncrement) {
      alert(`La oferta debe ser al menos ${currentPrice + item.minIncrement}`);
      return;
    }

    // Anti-sniping logic
    const now = Date.now();
    const remaining = (item.endTime || 0) - now;
    let newEndTime = item.endTime;
    if (remaining > 0 && remaining < 30000) {
      newEndTime = now + 30000;
    }

    // Transacción: Insertar puja y actualizar item
    const { error: bidError } = await supabase.from('bids').insert({
      itemId,
      userId: currentUser.id,
      amount,
      timestamp: now
    });

    if (!bidError) {
      await supabase.from('items').update({ 
        currentBid: amount, 
        endTime: newEndTime 
      }).eq('id', itemId);
    }
  };

  const activateBidding = async (itemId: string, durationSeconds: number) => {
    await supabase.from('items').update({ 
      status: ItemStatus.ACTIVE_BIDDING, 
      endTime: Date.now() + (durationSeconds * 1000) 
    }).eq('id', itemId);
  };

  const adjudicateItem = async (itemId: string) => {
    const lastBid = bids.filter(b => b.itemId === itemId).sort((a,b) => b.amount - a.amount)[0];
    await supabase.from('items').update({ 
      status: ItemStatus.ADJUDICATED,
      winnerId: lastBid?.userId 
    }).eq('id', itemId);
  };

  // Timer local para cerrar pujas que expiran
  useEffect(() => {
    const interval = setInterval(async () => {
      const now = Date.now();
      const expiredItems = items.filter(item => 
        item.status === ItemStatus.ACTIVE_BIDDING && item.endTime && now > item.endTime
      );

      for (const item of expiredItems) {
        await supabase.from('items').update({ status: ItemStatus.CLOSED }).eq('id', item.id);
      }
    }, 5000);
    return () => clearInterval(interval);
  }, [items]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="font-bold text-slate-600 animate-pulse">Sincronizando con Subas-tica Cloud...</p>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <div className="min-h-screen flex flex-col">
        {currentUser && <Navbar user={currentUser} onLogout={handleLogout} />}

        <main className="flex-1 overflow-auto">
          <Routes>
            <Route 
              path="/" 
              element={currentUser ? <Navigate to={`/${currentUser.role.toLowerCase()}`} /> : <LandingPage onLogin={handleLogin} />} 
            />

            <Route 
              path="/buyer" 
              element={currentUser?.role === UserRole.BUYER ? 
                <BuyerDashboard items={items} onInterest={handleInterest} onBuyIntent={handleBuyIntent} userId={currentUser.id} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/admin" 
              element={currentUser?.role === UserRole.ADMIN ? 
                <AdminDashboard items={items} bids={bids} onActivate={activateBidding} onAdjudicate={adjudicateItem} onUpdateStatus={updateItemStatus} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/seller" 
              element={currentUser?.role === UserRole.SELLER ? 
                <SellerDashboard items={items} sellerId={currentUser.id} /> : 
                <Navigate to="/" />} 
            />

            <Route 
              path="/item/:id" 
              element={<ItemDetail 
                items={items} 
                bids={bids} 
                user={currentUser} 
                onInterest={handleInterest} 
                onBuyIntent={handleBuyIntent} 
                onBid={placeBid} 
              />} 
            />

            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

