                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 rounded-2xl p-4 border border-slate-100">
                      <p className="text-[10px] uppercase font-black text-slate-400 tracking-wider mb-1">Oferta</p>
                      <p className="text-2xl font-black text-slate-800">${(item.currentBid || item.basePrice).toLocaleString()}</p>
                    </div>
                    <div className="bg-slate-50 rounded-2xl p-4 border border-slate-100">
                      <p className="text-[10px] uppercase font-black text-slate-400 tracking-wider mb-1">Postores</p>
                      <p className="text-2xl font-black text-slate-800">{new Set(itemBids.map(b => b.userId)).size}</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <button 
                      onClick={() => onUpdateStatus(item.id, ItemStatus.PAUSED)}
                      className="bg-amber-100 text-amber-600 py-3 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-amber-200 transition-colors"
                    >
                      Pausar
                    </button>
                    <button 
                      onClick={() => onUpdateStatus(item.id, ItemStatus.CLOSED)}
                      className="bg-slate-800 text-white py-3 rounded-2xl text-xs font-black uppercase tracking-widest hover:bg-slate-900 transition-colors shadow-lg"
                    >
                      Cerrar
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </section>
      )}

