              <tr className="bg-slate-50/50 text-slate-400 text-[10px] font-black uppercase tracking-widest border-b border-slate-100">
                <th className="px-8 py-5">Identificación Lote</th>
                <th className="px-8 py-5">Estado Operativo</th>
                <th className="px-8 py-5">Demanda (Interés/Compra)</th>
                <th className="px-8 py-5">Valoración</th>
                <th className="px-8 py-5 text-right">Acciones de Control</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50/30 transition-colors group">
